import { useState, useEffect } from 'react';
import { getAllSchedules, updateAvailability, createSchedule } from '../utils/api';
import toast from 'react-hot-toast';
import { ChevronDown, Plus, List as ListIcon, Calendar, MoreVertical } from 'lucide-react';
import './Availability.css';

const DAYS = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];

const TIMEZONES = [
  'America/New_York', 'America/Chicago', 'America/Denver', 'America/Los_Angeles',
  'Europe/London', 'Europe/Paris',
  'Asia/Tokyo', 'Asia/Kolkata',
  'Australia/Sydney'
];

const TIME_OPTIONS = [];
for (let h = 0; h < 24; h++) {
  for (let m = 0; m < 60; m += 30) {
    const hStr = h.toString().padStart(2, '0');
    const mStr = m.toString().padStart(2, '0');
    const val = `${hStr}:${mStr}`;
    const hour12 = h === 0 ? 12 : h > 12 ? h - 12 : h;
    const ampm = h < 12 ? 'AM' : 'PM';
    TIME_OPTIONS.push({ value: val, label: `${hour12}:${mStr} ${ampm}` });
  }
}

export default function Availability() {
  const [schedules, setSchedules] = useState([]);
  const [activeScheduleId, setActiveScheduleId] = useState(null);
  const [schedule, setSchedule] = useState(null);

  const [showScheduleDropdown, setShowScheduleDropdown] = useState(false);
  const [slots, setSlots] = useState({});
  const [timezone, setTimezone] = useState('America/New_York');
  const [saving, setSaving] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchSchedules();
  }, []);

  async function fetchSchedules() {
    try {
      const { data } = await getAllSchedules();
      setSchedules(data);
      if (data.length > 0) {
        const def = data.find(s => s.is_default) || data[0];
        setActiveScheduleId(def.id);
        applyScheduleData(def);
      }
    } finally {
      setLoading(false);
    }
  }

  function applyScheduleData(data) {
    setSchedule(data);
    setTimezone(data.timezone);
    const slotsMap = {};
    for (let d = 0; d < 7; d++) {
      const slot = data.slots.find(s => s.day_of_week === d);
      slotsMap[d] = slot
        ? { enabled: slot.is_active, start: slot.start_time, end: slot.end_time }
        : { enabled: false, start: '09:00', end: '17:00' };
    }
    setSlots(slotsMap);
  }

  function switchSchedule(id) {
    const s = schedules.find(x => x.id === id);
    if (s) {
      setActiveScheduleId(id);
      applyScheduleData(s);
    }
    setShowScheduleDropdown(false);
  }

  async function handleCreateSchedule() {
    const name = window.prompt("Enter new schedule name:");
    if (!name) return;
    try {
      const { data } = await createSchedule({ name, timezone });
      setSchedules([...schedules, data]);
      switchSchedule(data.id);
      toast.success("Schedule created!");
    } catch {
      toast.error("Failed to create schedule");
    }
  }

  function toggleDay(day) {
    setSlots(s => ({
      ...s,
      [day]: { ...s[day], enabled: !s[day].enabled }
    }));
  }

  function updateSlot(day, field, value) {
    setSlots(s => ({
      ...s,
      [day]: { ...s[day], [field]: value }
    }));
  }

  async function handleSave() {
    if (!activeScheduleId) return;
    setSaving(true);
    try {
      const slotsData = Object.entries(slots)
        .filter(([, s]) => s.enabled)
        .map(([day, s]) => ({
          day_of_week: parseInt(day),
          start_time: s.start,
          end_time: s.end,
          is_active: true,
        }));

      const { data } = await updateAvailability(activeScheduleId, { timezone, slots: slotsData });
      setSchedules(schedules.map(s => s.id === activeScheduleId ? data : s));
      toast.success('Availability saved!');
    } catch {
      toast.error('Failed to save');
    } finally {
      setSaving(false);
    }
  }

  if (loading) {
    return (
      <div className="page-inner">
        <div className="loading-skeleton" />
      </div>
    );
  }

  return (
    <div className="page-inner">
      <div className="page-header">
        <div>
          <h1 className="page-title">Availability</h1>
          <p className="page-subtitle">Set when you're available for meetings</p>
        </div>
        <button className="btn btn-primary" onClick={handleSave} disabled={saving}>
          {saving ? <span className="spinner" /> : null}
          Save Changes
        </button>
      </div>

      <div style={{ display: 'flex', flexDirection: 'column', gap: 0, marginBottom: 40 }}>
        {/* Schedule Header / Dropdown UI */}
        <div style={{ padding: '24px 32px', background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: 'var(--radius-xl) var(--radius-xl) 0 0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <div>
            <div style={{ fontSize: 13, color: 'var(--text-secondary)', fontWeight: 600, marginBottom: 4 }}>Schedule</div>
            <div style={{ position: 'relative' }}>
              <button 
                className="btn btn-secondary" 
                style={{ fontSize: 18, fontWeight: 700, color: 'var(--blue)', border: 'none', background: 'transparent', padding: '0', display: 'flex', alignItems: 'center', gap: 6 }}
                onClick={() => setShowScheduleDropdown(!showScheduleDropdown)}
              >
                {schedule?.name || 'Working hours'} {schedule?.is_default ? '(default)' : ''}
                <ChevronDown size={18} />
              </button>

              {showScheduleDropdown && (
                <>
                  <div style={{ position: 'fixed', inset: 0, zIndex: 9 }} onClick={() => setShowScheduleDropdown(false)} />
                  <div style={{ position: 'absolute', top: '100%', left: 0, marginTop: 8, background: 'var(--surface)', border: '1px solid var(--border)', borderRadius: 'var(--radius-lg)', boxShadow: 'var(--shadow-lg)', width: 280, zIndex: 10, overflow: 'hidden' }}>
                    <div style={{ display: 'flex', flexDirection: 'column' }}>
                      {schedules.map(s => (
                        <button 
                          key={s.id}
                          style={{ padding: '12px 16px', display: 'flex', justifyContent: 'space-between', background: 'transparent', border: 'none', cursor: 'pointer', textAlign: 'left', fontSize: 14, color: activeScheduleId === s.id ? 'var(--blue)' : 'var(--text-primary)', fontWeight: activeScheduleId === s.id ? 600 : 400, borderBottom: '1px solid var(--border)' }}
                          onClick={() => switchSchedule(s.id)}
                        >
                          <span>{s.name} {s.is_default ? '(default)' : ''}</span>
                          {activeScheduleId === s.id && <span>✓</span>}
                        </button>
                      ))}
                    </div>
                    <button 
                      style={{ padding: '12px 16px', display: 'flex', alignItems: 'center', gap: 8, background: 'transparent', border: 'none', cursor: 'pointer', width: '100%', textAlign: 'left', fontSize: 14, color: 'var(--text-secondary)' }}
                      onClick={handleCreateSchedule}
                    >
                      <Plus size={16} /> Create schedule
                    </button>
                  </div>
                </>
              )}
            </div>
          </div>

          {/* Right side controls from the mockup */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
             <div style={{ display: 'flex', border: '1px solid var(--border)', borderRadius: 99, overflow: 'hidden' }}>
               <button style={{ padding: '8px 16px', background: 'var(--surface)', border: 'none', borderRight: '1px solid var(--border)', display: 'flex', alignItems: 'center', gap: 6, fontSize: 14, fontWeight: 600 }}>
                 <ListIcon size={16} /> List
               </button>
               <button style={{ padding: '8px 16px', background: '#f8fafc', border: 'none', display: 'flex', alignItems: 'center', gap: 6, fontSize: 14, color: 'var(--text-secondary)', cursor: 'pointer' }}>
                 <Calendar size={16} /> Calendar
               </button>
             </div>
             <button className="btn btn-secondary" style={{ padding: '8px', borderRadius: 99, border: 'none', cursor: 'pointer' }}>
               <MoreVertical size={18} />
             </button>
          </div>
        </div>

        <div className="avail-layout" style={{ borderRadius: '0 0 var(--radius-xl) var(--radius-xl)', borderTop: 'none', marginTop: 0 }}>
          <div className="avail-main card" style={{ borderRadius: '0 0 0 var(--radius-xl)', borderTop: 'none', boxShadow: 'none' }}>
            <div className="avail-section-header">
              <h3>Weekly Hours</h3>
              <p>Set your regular working hours for each day of the week</p>
            </div>

            <div className="days-list">
              {DAYS.map((name, i) => (
                <div key={i} className={`day-row ${slots[i]?.enabled ? 'enabled' : ''}`}>
                  <label className="day-toggle">
                    <input
                      type="checkbox"
                      checked={slots[i]?.enabled || false}
                      onChange={() => toggleDay(i)}
                      className="toggle-input"
                    />
                    <span className="toggle-track">
                      <span className="toggle-thumb" />
                    </span>
                    <span className="day-name">{name}</span>
                  </label>

                  {slots[i]?.enabled ? (
                    <div className="time-range">
                      <select
                        className="form-input form-select time-select"
                        value={slots[i]?.start}
                        onChange={e => updateSlot(i, 'start', e.target.value)}
                      >
                        {TIME_OPTIONS.map(t => (
                          <option key={t.value} value={t.value}>{t.label}</option>
                        ))}
                      </select>
                      <span className="time-dash">–</span>
                      <select
                        className="form-input form-select time-select"
                        value={slots[i]?.end}
                        onChange={e => updateSlot(i, 'end', e.target.value)}
                      >
                        {TIME_OPTIONS.map(t => (
                          <option key={t.value} value={t.value}>{t.label}</option>
                        ))}
                      </select>
                    </div>
                  ) : (
                    <span className="unavailable-label">Unavailable</span>
                  )}
                </div>
              ))}
            </div>
          </div>

          <div className="avail-sidebar">
            <div className="card" style={{ padding: 22, borderRadius: '0 0 var(--radius-xl) 0', borderTop: 'none', boxShadow: 'none', height: '100%' }}>
              <h3 style={{ fontSize: 15, fontWeight: 700, marginBottom: 6 }}>Timezone</h3>
              <p style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 14 }}>
                All availability times are based on this timezone
              </p>
              <select
                className="form-input form-select"
                value={timezone}
                onChange={e => setTimezone(e.target.value)}
              >
                {TIMEZONES.map(tz => (
                  <option key={tz} value={tz}>{tz.replace('_', ' ')}</option>
                ))}
              </select>

              <h3 style={{ fontSize: 15, fontWeight: 700, marginBottom: 6, marginTop: 32 }}>Quick Setup</h3>
              <p style={{ fontSize: 13, color: 'var(--text-muted)', marginBottom: 14 }}>
                Apply a common schedule preset
              </p>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                <button
                  className="btn btn-secondary btn-sm"
                  style={{ justifyContent: 'flex-start' }}
                  onClick={() => {
                    const s = {};
                    for (let i = 0; i < 7; i++) {
                      s[i] = { enabled: i < 5, start: '09:00', end: '17:00' };
                    }
                    setSlots(s);
                  }}
                >
                  Mon–Fri, 9am–5pm
                </button>
                <button
                  className="btn btn-secondary btn-sm"
                  style={{ justifyContent: 'flex-start' }}
                  onClick={() => {
                    const s = {};
                    for (let i = 0; i < 7; i++) {
                      s[i] = { enabled: i < 6, start: '08:00', end: '18:00' };
                    }
                    setSlots(s);
                  }}
                >
                  Mon–Sat, 8am–6pm
                </button>
                <button
                  className="btn btn-secondary btn-sm"
                  style={{ justifyContent: 'flex-start' }}
                  onClick={() => {
                    const s = {};
                    for (let i = 0; i < 7; i++) {
                      s[i] = { enabled: true, start: '10:00', end: '20:00' };
                    }
                    setSlots(s);
                  }}
                >
                  Every day, 10am–8pm
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
